  it("accepts valid events and returns accepted count", async () => {
    const batchMock = vi.fn().mockResolvedValue([]);
    const db = {
      prepare: vi.fn().mockReturnValue({
        bind: vi.fn().mockReturnThis(),
        run: vi.fn().mockResolvedValue({}),
